INSERT INTO `tb_eviden_trafo` VALUES (1,31,109,'PA376','2026-01-28','Selesai perbaikan PA376 TO Hotspot fuse holder line C phase R 89°C, Baut plat cover sisi out helbom phase T 92°C. Lokasi perum permata taman delta Blok K. Zona 2. P. Klurak bali.\r\nPerbaikan dan pengencangan keseluruhan baut busbar\r\nMaterial Terpakai : \r\nNH FUSE 224A 1bh\r\nKunci pintu panel 1 set','2026-02-01 01:11:24'),(2,31,108,'PA1166','2026-01-06','Selesai perbaikan Pa1166 hospot joint Alcu phase T line D 177°c, phase N 85°c. Lokasi perum heavenland. Zona2. P. Heavenland\r\nMaterial Terpakai : \r\nLine Tap 35x70mm = 6bh','2026-02-01 12:50:05'),(3,13,44,'PA708','2026-01-06','Selesai perbaikan PA708 Hotspot fuse holder Line C phase S 106°C , phase T 90°C. Lokasi perum bluru permai Blok C1-9(memo pemerataan beban) . Zona 2. P. Prasung\r\nMaterial Terpakai : \r\nNH Fuse 250A = 1bh\r\nLine Tap 35x70mm = 8bh\r\n','2026-02-01 12:58:14'),(4,13,44,'PA1134','2026-02-06','Selesai perbaikan PA1134 Hotspot jumperan joint phas R line A 112°C, memo Pemerataan beban Lokasi Prm Bluru permai Blok H P.prasung\r\nMaterial Terpakai : \r\nJoint ALCU 70mm = 1bh\r\nLine Tap 35x70mm = 3bh','2026-02-01 13:02:18'),(5,13,44,'PA592','2026-01-06','Selesai perbaikan PA592 memo pemerataan beban. Lokasi perum bluru permai zona2. P. Prasung\r\nMaterial Terpakai : \r\nLine Tap 35x70mm = 5bh\r\n','2026-02-01 13:06:14'),(6,43,160,'PA752','2026-01-07','Selesai perbaikan PA752 Hotspot Skun Line Utama phase R sisi out 105°C , Hotspot skun Line utama phase R sisi in 114°C. Hotspot fuse holder Line D phase R 137°C. Lokasi Barat Salon Salma dusun gesing desa banjarsari. Zona 2. P. Jayaland.\r\nPerbaikan dan pengencangan busbar.\r\nMaterial Terpakai :\r\nHelbom 630A 1bh\r\nSkun CU 150mm 2bh\r\nLine tap 25x35mm 8bh\r\nNH Fuse 250A 3bh\r\nCover bushing 1 set\r\nCover LA 1 Set\r\n','2026-02-01 13:15:00');
