--
-- Table structure for table `temuan`
--

DROP TABLE IF EXISTS `temuan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `temuan` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `nomor_temuan` varchar(50) NOT NULL,
  `ulp_id` int(11) unsigned NOT NULL,
  `penyulang_id` int(11) unsigned NOT NULL,
  `section_id` int(11) unsigned NOT NULL,
  `jenis_temuan` varchar(50) NOT NULL,
  `pelaksana` varchar(50) NOT NULL,
  `prioritas` varchar(50) NOT NULL,
  `potensi_gangguan` varchar(50) NOT NULL,
  `konduktor` varchar(100) DEFAULT NULL,
  `noga` varchar(100) DEFAULT NULL,
  `material` text DEFAULT NULL,
  `detail_temuan` text DEFAULT NULL,
  `alamat` text DEFAULT NULL,
  `latitude` decimal(10,8) DEFAULT NULL,
  `longitude` decimal(11,8) DEFAULT NULL,
  `tanggal_temuan` date NOT NULL,
  `tanggal_selesai` date DEFAULT NULL,
  `foto` text DEFAULT NULL,
  `status` varchar(20) NOT NULL DEFAULT 'BELUM',
  `created_by` int(11) unsigned DEFAULT NULL,
  `created_by_name` varchar(100) DEFAULT NULL,
  `created_by_nip` varchar(50) DEFAULT NULL,
  `updated_by` int(11) unsigned DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  `foto_path` varchar(255) DEFAULT NULL,
  `tindak_lanjut` text DEFAULT NULL,
  `catatan_tindak_lanjut` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `nomor_temuan` (`nomor_temuan`),
  KEY `temuan_ulp_id_foreign` (`ulp_id`),
  KEY `temuan_penyulang_id_foreign` (`penyulang_id`),
  KEY `temuan_section_id_foreign` (`section_id`),
  CONSTRAINT `temuan_penyulang_id_foreign` FOREIGN KEY (`penyulang_id`) REFERENCES `penyulang` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `temuan_section_id_foreign` FOREIGN KEY (`section_id`) REFERENCES `sections` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
